mapper.select:
SELECT id, tenant_id, report_id, task_type, status, priority, parameters, progress,
       result, error_message, parent_task_id, shard_seq, shard_total, created_by,
       created_at, started_at, completed_at, cancelled_at
FROM task
WHERE tenant_id = #{tenantId}

    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM task
WHERE tenant_id = #{tenantId}

    AND status = #{status}

SELECT COUNT(*)
FROM task
WHERE tenant_id = #{tenantId} AND status = #{status}
